834→  <!-- Anonymous Contact Form Submission -->
835→  <script>
836→    function submitContactForm(event) {
837→      event.preventDefault();
838→      var messageEl = document.getElementById('contact-message');
839→      var nameEl = document.getElementById('contact-name');
840→      var emailEl = document.getElementById('contact-email');
841→      var urlEl = document.getElementById('contact-url');
842→      var categoryEl = document.getElementById('contact-category');
843→      var statusEl = document.getElementById('form-status');
844→      var message = messageEl.value.trim();
845→
846→      if (!message) return;
847→
848→      statusEl.textContent = 'Sending...';
849→      statusEl.className = 'mt-3 text-sm text-gray-400';
850→
851→      var webhookUrl = 'https://n8n.cloudpublica.org/webhook/justnice-contact';
852→
853→      fetch(webhookUrl, {
854→        method: 'POST',
855→        headers: { 'Content-Type': 'application/json' },
856→        body: JSON.stringify({
857→          message: message,
858→          name: nameEl.value.trim(),
859→          email: emailEl.value.trim(),
860→          url: urlEl.value.trim(),
861→          category: categoryEl.value,
862→          source: 'justnice.us/blog/atx-ice-activity',
863→          page: window.location.pathname,
864→          timestamp: new Date().toISOString()
865→        })
866→      })
867→      .then(function (response) {
868→        if (response.ok) {
869→          statusEl.textContent = 'Thank you! Your message has been sent.';
870→          statusEl.className = 'mt-3 text-sm text-green-400';
871→          messageEl.value = '';
872→          nameEl.value = '';
873→          emailEl.value = '';
874→          urlEl.value = '';
875→          categoryEl.value = '';
876→        } else {
877→          throw new Error('Network response was not ok');
878→        }
879→      })
880→      .catch(function () {
881→        statusEl.textContent = 'Something went wrong. Please try again.';
882→        statusEl.className = 'mt-3 text-sm text-red-400';
883→      });
884→    }
885→  </script>
