// Define all RSS feeds to monitor
const feeds = [
  { name: 'Drop Site News', url: 'https://www.dropsitenews.com/feed', focus: 'Immigration investigative' },
  { name: 'ProPublica Immigration', url: 'https://www.propublica.org/feeds/topics/immigration', focus: 'National investigations' },
  { name: 'Texas Tribune Immigration', url: 'https://www.texastribune.org/feeds/tag/immigration/', focus: 'Texas-specific' },
  { name: 'KERA News Immigration', url: 'https://www.keranews.org/immigration/rss', focus: 'DFW / North Texas' },
  { name: 'El Paso Matters', url: 'https://elpasomatters.org/feed/', focus: 'Border region' },
  { name: 'Houston Public Media', url: 'https://www.houstonpublicmedia.org/topics/immigration/feed/', focus: 'Houston area' },
  { name: 'Border Report', url: 'https://www.borderreport.com/feed/', focus: 'Border states' },
  { name: 'ICE.gov News Releases', url: 'https://www.ice.gov/newsroom/news-releases/rss', focus: 'Official ICE' },
  { name: 'DOJ WDTX Press Releases', url: 'https://www.justice.gov/usao-wdtx/press-releases/feed', focus: 'Western District TX' },
  { name: 'ACLU Immigration', url: 'https://www.aclu.org/issues/immigrants-rights/feed', focus: 'Legal challenges' }
];

return feeds.map(f => ({ json: f }));

// Extract RSS items and filter to last 24 hours
const now = new Date();
const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const results = [];

for (const item of $input.all()) {
  try {
    const data = item.json.data || item.json;
    const feed = data.rss?.channel || data.feed || data;
    const feedTitle = feed.title || 'Unknown Feed';

    // Handle both RSS 2.0 (<item>) and Atom (<entry>) formats
    let entries = feed.item || feed.entry || [];
    if (!Array.isArray(entries)) entries = [entries];

    for (const entry of entries) {
      if (!entry) continue;

      const pubDateStr = entry.pubDate || entry.published || entry.updated || entry['dc:date'] || '';
      const pubDate = new Date(pubDateStr);

      // Filter: only last 24 hours
      if (pubDate < oneDayAgo || isNaN(pubDate.getTime())) continue;

      const title = entry.title || 'No title';
      const link = entry.link?.href || entry.link || '';
      const description = entry.description || entry.summary || entry.content || '';
      // Strip HTML tags from description
      const cleanDesc = typeof description === 'string' 
        ? description.replace(/<[^>]*>/g, '').substring(0, 500) 
        : '';

      results.push({
        json: {
          title: typeof title === 'object' ? title._ || title['#text'] || JSON.stringify(title) : title,
          link: typeof link === 'object' ? link.href || '' : link,
          pubDate: pubDate.toISOString(),
          source: typeof feedTitle === 'object' ? feedTitle._ || JSON.stringify(feedTitle) : feedTitle,
          description: cleanDesc,
          type: 'rss'
        }
      });
    }
  } catch (e) {
    // Skip feeds that fail to parse
    continue;
  }
}

if (results.length === 0) {
  return [{ json: { title: 'No new items', link: '', pubDate: now.toISOString(), source: 'System', description: 'No RSS items found in last 24 hours.', type: 'none' } }];
}

return results;

// Normalize CourtListener results
const results = [];

for (const item of $input.all()) {
  const data = item.json;
  const opinions = data.results || [];

  for (const op of opinions) {
    results.push({
      json: {
        title: op.caseName || op.case_name || 'Court Opinion',
        link: `https://www.courtlistener.com${op.absolute_url || ''}`,
        pubDate: op.dateFiled || op.date_filed || new Date().toISOString(),
        source: `CourtListener — ${op.court || op.court_id || 'Federal Court'}`,
        description: (op.snippet || op.text || '').substring(0, 500),
        type: 'legal'
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { title: 'No new court opinions', link: '', pubDate: new Date().toISOString(), source: 'CourtListener', description: 'No new immigration court opinions in last 24 hours.', type: 'none' } }];
}

return results;

// Extract key stats from ICE ERO page HTML
const html = $input.first().json.data || '';
const results = [];

// Look for key numbers in the page
const patterns = [
  { regex: /([\d,]+)\s*(?:arrests|apprehensions)/gi, label: 'Arrests' },
  { regex: /([\d,]+)\s*(?:removals|deportations|removed)/gi, label: 'Removals' },
  { regex: /([\d,]+)\s*(?:detained|in custody|detainees)/gi, label: 'Detained' }
];

let statsFound = [];
for (const p of patterns) {
  const match = p.regex.exec(html);
  if (match) {
    statsFound.push(`${p.label}: ${match[1]}`);
  }
}

if (statsFound.length > 0) {
  results.push({
    json: {
      title: 'ICE ERO Enforcement Statistics Update',
      link: 'https://www.ice.gov/spotlight/enforcement-and-removal-operations',
      pubDate: new Date().toISOString(),
      source: 'ICE.gov',
      description: `Updated enforcement statistics from ICE ERO spotlight page. ${statsFound.join('; ')}.`,
      type: 'data'
    }
  });
} else {
  results.push({
    json: {
      title: 'ICE ERO page checked — no parseable updates',
      link: 'https://www.ice.gov/spotlight/enforcement-and-removal-operations',
      pubDate: new Date().toISOString(),
      source: 'ICE.gov',
      description: 'ICE ERO spotlight page was checked but no new stats could be extracted automatically.',
      type: 'none'
    }
  });
}

return results;

// Remove placeholder 'none' type items and deduplicate by URL
const seen = new Set();
const results = [];

for (const item of $input.all()) {
  const d = item.json;
  if (d.type === 'none') continue;
  if (!d.title || !d.link) continue;

  // Deduplicate by URL
  const key = d.link.replace(/\/$/, '').toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  results.push(item);
}

if (results.length === 0) {
  return [{ json: { _empty: true, message: 'No items found today' } }];
}

return results;

// Parse the AI agent's JSON output into individual items
const output = $input.first().json.output || $input.first().json.text || '';
let classified = [];

try {
  // Try to extract JSON array from the response
  let jsonStr = output;

  // Remove markdown code fencing if present
  const jsonMatch = jsonStr.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    jsonStr = jsonMatch[0];
  }

  classified = JSON.parse(jsonStr);
} catch (e) {
  // If parsing fails, return the raw output for manual review
  return [{ json: { error: 'Failed to parse AI output', raw: output, parseError: e.message } }];
}

if (!Array.isArray(classified) || classified.length === 0) {
  return [{ json: { error: 'No classified items', raw: output } }];
}

return classified.map(item => ({ json: item }));

// Generate HTML snippets per justNICE template format
const items = $input.all().map(i => i.json);

// Skip if there was a parse error
if (items.length === 1 && items[0].error) {
  return [{ json: { htmlSnippets: '', digest: items[0].error, rawItems: items } }];
}

// Group by state
const byState = {};
const highPriority = [];

for (const item of items) {
  const states = Array.isArray(item.state) ? item.state : [item.state || 'US'];

  if (item.severity === 'high') {
    highPriority.push(item);
  }

  for (const st of states) {
    if (!byState[st]) byState[st] = [];
    byState[st].push(item);
  }
}

// Format date nicely
function fmtDate(d) {
  try {
    return new Date(d).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
  } catch { return d; }
}

// Generate HTML snippets
let fnNum = 1;
const footnotes = [];
let htmlByState = {};

for (const [state, stateItems] of Object.entries(byState)) {
  const snippets = stateItems.map(item => {
    const currentFn = fnNum++;
    footnotes.push({ num: currentFn, url: item.sourceUrl, source: item.sourceName });

    return `<h3 class="text-xl md:text-2xl font-semibold text-maroon mt-8 mb-3">
  ${fmtDate(item.date)} — ${item.title}
</h3>
<p>
  ${item.summary}
  <sup><a href="#fn${currentFn}" class="fn-ref">[${currentFn}]</a></sup>
</p>`;
  });

  htmlByState[state] = snippets.join('\n');
}

// Build digest text
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });

let digest = `## ICE Activity Digest — ${today}\n\n`;
digest += `**Total items:** ${items.length}\n\n`;

if (highPriority.length > 0) {
  digest += `### 🚨 High Priority\n`;
  for (const hp of highPriority) {
    const states = Array.isArray(hp.state) ? hp.state.join(', ') : hp.state;
    digest += `- **[${states}]** ${hp.title} (${hp.sourceName})\n`;
  }
  digest += '\n';
}

digest += `### By State\n`;
const sortedStates = Object.keys(byState).sort();
for (const st of sortedStates) {
  digest += `**${st}** (${byState[st].length} items)\n`;
  for (const item of byState[st]) {
    digest += `- [${item.category}] ${item.title}${item.numbers ? ' (' + item.numbers + ')' : ''}\n`;
  }
  digest += '\n';
}

// Build footnotes HTML
const footnotesHtml = footnotes.map(fn => 
  `<li id="fn${fn.num}"><a href="${fn.url}" target="_blank" rel="noopener noreferrer">${fn.source}: ${fn.url}</a></li>`
).join('\n');

return [{
  json: {
    digest,
    htmlByState,
    footnotesHtml,
    highPriorityCount: highPriority.length,
    totalItems: items.length,
    statesAffected: sortedStates,
    classifiedItems: items
  }
}];

