          "jsCode": "const now = new Date();\nconst oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);\nconst results = [];\n\nfor (const item of $input.all()) {\n  try {\n    const data = item.json.data || item.json;\n    const feed = data.rss?.channel || data.feed || data;\n    const feedTitle = feed.title || 'Unknown Feed';\n    let entries = feed.item || feed.entry || [];\n    if (!Array.isArray(entries)) entries = [entries];\n    \n    for (const entry of entries) {\n      if (!entry) continue;\n      const pubDateStr = entry.pubDate || entry.published || entry.updated || entry['dc:date'] || '';\n      const pubDate = new Date(pubDateStr);\n      if (pubDate < oneDayAgo || isNaN(pubDate.getTime())) continue;\n      \n      const title = entry.title || 'No title';\n      const link = entry.link?.href || entry.link || '';\n      const description = entry.description || entry.summary || entry.content || '';\n      const cleanDesc = typeof description === 'string' ? description.replace(/<[^>]*>/g, '').substring(0, 500) : '';\n      \n      results.push({ json: {\n        title: typeof title === 'object' ? title._ || title['#text'] || JSON.stringify(title) : title,\n        link: typeof link === 'object' ? link.href || '' : link,\n        pubDate: pubDate.toISOString(),\n        source: typeof feedTitle === 'object' ? feedTitle._ || JSON.stringify(feedTitle) : feedTitle,\n        description: cleanDesc,\n        type: 'rss'\n      }});\n    }\n  } catch (e) { continue; }\n}\n\nif (results.length === 0) {\n  return [{ json: { title: 'No new items', link: '', pubDate: now.toISOString(), source: 'System', description: 'No RSS items found in last 24 hours.', type: 'none' } }];\n}\nreturn results;"
