          "jsCode": "const seen = new Set();\nconst results = [];\nfor (const item of $input.all()) {\n  const d = item.json;\n  if (d.type === 'none') continue;\n  if (!d.title || !d.link) continue;\n  const key = d.link.replace(/\\/$/, '').toLowerCase();\n  if (seen.has(key)) continue;\n  seen.add(key);\n  results.push(item);\n}\nif (results.length === 0) {\n  return [{ json: { _empty: true, message: 'No items found today', itemCount: 0 } }];\n}\nreturn results;"
        }
