          "jsCode": "const items = $input.all().map(i => i.json);\n\n// If no items, pass through empty signal\nif (items.length === 1 && items[0]._empty) {\n  return [{ json: { _empty: true, message: items[0].message, chatInput: 'No items to classify today.' } }];\n}\n\n// Build the prompt with all items\nconst itemList = items.map((item, i) => \n  (i+1) + '. ' + item.title + ' (' + item.source + ', ' + item.pubDate + ')\\nURL: ' + item.link + '\\n' + item.description\n).join('\\n\\n');\n\nconst prompt = 'Here are ' + items.length + ' news items about immigration enforcement collected today. Classify each one.\\n\\n' + itemList + '\\n\\nFor each item, return a JSON array where each element has:\\n- state: 2-letter abbreviation(s) of US state(s) it relates to (use \"US\" if national/multi-state)\\n- category: one of raid, arrest, detention, deportation, legal, policy, community-response, economic-impact, facility, other\\n- severity: high, medium, or low\\n- title: short headline (max 80 chars)\\n- summary: 2-3 sentence summary of what happened, where, when, how many affected\\n- numbers: any specific counts (arrests, detentions, etc.) or null\\n- sourceUrl: the original link\\n- sourceName: the source name\\n- date: the publication date\\n\\nReturn ONLY a valid JSON array, no markdown fencing.';\n\nreturn [{ json: { chatInput: prompt, _empty: false, itemCount: items.length } }];"
