      {
        "id": "format-digest",
        "name": "Format Digest & HTML",
        "type": "n8n-nodes-base.code",
        "typeVersion": 2,
        "position": [
          2480,
          500
        ],
        "parameters": {
          "mode": "runOnceForAllItems",
          "jsCode": "const items = $input.all().map(i => i.json);\nif (items.length === 1 && items[0].error) {\n  return [{ json: { htmlSnippets: '', digest: items[0].error, rawItems: items, totalItems: 0, highPriorityCount: 0 } }];\n}\n\nconst byState = {};\nconst highPriority = [];\nfor (const item of items) {\n  const states = Array.isArray(item.state) ? item.state : [item.state || 'US'];\n  if (item.severity === 'high') highPriority.push(item);\n  for (const st of states) {\n    if (!byState[st]) byState[st] = [];\n    byState[st].push(item);\n  }\n}\n\nfunction fmtDate(d) {\n  try { return new Date(d).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' }); }\n  catch { return d; }\n}\n\nlet fnNum = 1;\nconst footnotes = [];\nlet htmlByState = {};\nfor (const [state, stateItems] of Object.entries(byState)) {\n  htmlByState[state] = stateItems.map(item => {\n    const currentFn = fnNum++;\n    footnotes.push({ num: currentFn, url: item.sourceUrl, source: item.sourceName });\n    return '<h3 class=\"text-xl md:text-2xl font-semibold text-maroon mt-8 mb-3\">\\n  ' + fmtDate(item.date) + ' — ' + item.title + '\\n</h3>\\n<p>\\n  ' + item.summary + '\\n  <sup><a href=\"#fn' + currentFn + '\" class=\"fn-ref\">[' + currentFn + ']</a></sup>\\n</p>';\n  }).join('\\n');\n}\n\nconst today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });\nlet digest = '## ICE Activity Digest — ' + today + '\\n\\nTotal items: ' + items.length + '\\n\\n';\nif (highPriority.length > 0) {\n  digest += '### High Priority\\n';\n  for (const hp of highPriority) {\n    const states = Array.isArray(hp.state) ? hp.state.join(', ') : hp.state;\n    digest += '- [' + states + '] ' + hp.title + ' (' + hp.sourceName + ')\\n';\n  }\n  digest += '\\n';\n}\ndigest += '### By State\\n';\nconst sortedStates = Object.keys(byState).sort();\nfor (const st of sortedStates) {\n  digest += '**' + st + '** (' + byState[st].length + ' items)\\n';\n  for (const item of byState[st]) {\n    digest += '- [' + item.category + '] ' + item.title + (item.numbers ? ' (' + item.numbers + ')' : '') + '\\n';\n  }\n  digest += '\\n';\n}\n\nconst footnotesHtml = footnotes.map(fn => '<li id=\"fn' + fn.num + '\"><a href=\"' + fn.url + '\" target=\"_blank\" rel=\"noopener noreferrer\">' + fn.source + ': ' + fn.url + '</a></li>').join('\\n');\n\nreturn [{ json: { digest, htmlByState: JSON.stringify(htmlByState, null, 2), footnotesHtml, highPriorityCount: highPriority.length, totalItems: items.length, statesAffected: sortedStates.join(', ') } }];"
