767→  <!-- Blog category + keyword filter -->
768→  <script>
769→    (function () {
770→      var categorySelect = document.getElementById('blog-category');
771→      var searchInput = document.getElementById('blog-search');
772→      var cards = document.querySelectorAll('.blog-card');
773→
774→      function filterBlogCards() {
775→        var category = (categorySelect && categorySelect.value) ? categorySelect.value.trim() : '';
776→        var query = (searchInput && searchInput.value) ? searchInput.value.trim().toLowerCase() : '';
777→        var queryWords = query ? query.split(/\s+/) : [];
778→        var visible = 0;
779→
780→        cards.forEach(function (card) {
781→          var cardCategory = (card.getAttribute('data-category') || '').trim();
782→          var searchText = (card.getAttribute('data-search') || '').toLowerCase();
783→          var cardText = (card.textContent || '').toLowerCase();
784→          var fullText = searchText + ' ' + cardText;
785→
786→          var matchCategory = !category || cardCategory === category;
787→          var matchSearch = !queryWords.length || queryWords.every(function (word) {
788→            return fullText.indexOf(word) !== -1;
789→          });
790→          var show = matchCategory && matchSearch;
791→
792→          card.style.display = show ? '' : 'none';
793→          if (show) visible++;
794→        });
795→
796→        var noResults = document.getElementById('blog-no-results');
797→        if (noResults) noResults.classList.toggle('hidden', visible > 0);
798→      }
799→
800→      if (categorySelect) categorySelect.addEventListener('change', filterBlogCards);
801→      if (searchInput) {
802→        searchInput.addEventListener('input', filterBlogCards);
803→        searchInput.addEventListener('keyup', filterBlogCards);
804→      }
805→    })();
806→  </script>
