640→  <script>
641→    function submitContactForm(event) {
642→      event.preventDefault();
643→      var messageEl = document.getElementById('contact-message');
644→      var nameEl = document.getElementById('contact-name');
645→      var emailEl = document.getElementById('contact-email');
646→      var urlEl = document.getElementById('contact-url');
647→      var categoryEl = document.getElementById('contact-category');
648→      var statusEl = document.getElementById('form-status');
649→      var message = messageEl.value.trim();
650→
651→      if (!message) return;
652→
653→      statusEl.textContent = 'Sending...';
654→      statusEl.className = 'mt-3 text-sm text-gray-400';
655→
656→      // Replace this URL with your actual n8n webhook endpoint
657→      var webhookUrl = 'https://n8n.cloudpublica.org/webhook/justnice-contact';
658→
659→      fetch(webhookUrl, {
660→        method: 'POST',
661→        headers: { 'Content-Type': 'application/json' },
662→        body: JSON.stringify({
663→          message: message,
664→          name: nameEl.value.trim(),
665→          email: emailEl.value.trim(),
666→          url: urlEl.value.trim(),
667→          category: categoryEl.value,
668→          source: 'justnice.us',
669→          page: window.location.pathname,
670→          timestamp: new Date().toISOString()
671→        })
672→      })
673→      .then(function (response) {
674→        if (response.ok) {
675→          statusEl.textContent = 'Thank you! Your message has been sent.';
676→          statusEl.className = 'mt-3 text-sm text-green-400';
677→          messageEl.value = '';
678→          nameEl.value = '';
679→          emailEl.value = '';
680→          urlEl.value = '';
681→          categoryEl.value = '';
682→        } else {
683→          throw new Error('Network response was not ok');
684→        }
685→      })
686→      .catch(function () {
687→        statusEl.textContent = 'Something went wrong. Please try again.';
688→        statusEl.className = 'mt-3 text-sm text-red-400';
689→      });
690→    }
691→  </script>
